using Microsoft.AspNetCore.Http;
using System.IdentityModel.Tokens.Jwt;

public class JwtAuthenticationMiddleware : IMiddleware
{
    private readonly ILogger<JwtAuthenticationMiddleware> _logger;

    public JwtAuthenticationMiddleware(ILogger<JwtAuthenticationMiddleware> logger)
    {
        _logger = logger;
    }

    public async Task InvokeAsync(HttpContext context, RequestDelegate next)
    {
        var token = context.Request.Headers["Authorization"].FirstOrDefault();
        if (token != null && token.StartsWith("Bearer "))
        {
            token = token.Substring(7);
        }

        try
        {
            var jwtSecurityToken = new JwtSecurityTokenHandler().ReadJwtToken(token);
            if (jwtSecurityToken != null)
            {
                context.User = new ClaimsPrincipal(new ClaimsIdentity(jwtSecurityToken.Claims, "Bearer"));
            }
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Failed to authenticate user");
        }

        await next(context);
    }
}